import pygame
import random

# Constants
SCREEN_WIDTH = 800
SCREEN_HEIGHT = 600
GRID_SIZE = 30
GRID_WIDTH = SCREEN_WIDTH // GRID_SIZE
GRID_HEIGHT = SCREEN_HEIGHT // GRID_SIZE
FPS = 10

# Colors
COLORS = [
    (0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
    (255, 255, 0), (255, 165, 0), (128, 0, 128), (0, 255, 255)
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]]   # J
]

class Tetromino:
    def __init__(self):
        self.shape = random.choice(SHAPES)
        self.color = random.choice(COLORS)
        self.x = GRID_WIDTH // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Game:
    def __init__(self):
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_tetromino = Tetromino()
        self.score = [0, 0, 0]
        self.player_contributions = [0, 0, 0]
        self.current_player = 0
        self.game_over = False

    def draw_grid(self, screen):
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                color = COLORS[self.grid[y][x]]
                pygame.draw.rect(screen, color, (x * GRID_SIZE, y * GRID_SIZE, GRID_SIZE, GRID_SIZE), 0)

    def draw_tetromino(self, screen):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, self.current_tetromino.color,
                                     ((self.current_tetromino.x + x) * GRID_SIZE,
                                      (self.current_tetromino.y + y) * GRID_SIZE,
                                      GRID_SIZE, GRID_SIZE), 0)

    def check_collision(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    if (self.current_tetromino.x + x < 0 or
                        self.current_tetromino.x + x >= GRID_WIDTH or
                        self.current_tetromino.y + y >= GRID_HEIGHT or
                        self.grid[self.current_tetromino.y + y][self.current_tetromino.x + x]):
                        return True
        return False

    def merge_tetromino(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[self.current_tetromino.y + y][self.current_tetromino.x + x] = COLORS.index(self.current_tetromino.color)

    def clear_lines(self):
        lines_cleared = 0
        for y in range(GRID_HEIGHT):
            if all(self.grid[y]):
                lines_cleared += 1
                del self.grid[y]
                self.grid.insert(0, [0] * GRID_WIDTH)
        return lines_cleared

    def update_score(self, lines_cleared):
        if lines_cleared > 0:
            self.player_contributions[self.current_player] += lines_cleared
            self.score[self.current_player] += lines_cleared * 100

    def switch_player(self):
        self.current_player = (self.current_player + 1) % 3

    def run(self):
        pygame.init()
        screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        clock = pygame.time.Clock()

        while not self.game_over:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    self.game_over = True

            keys = pygame.key.get_pressed()
            if keys[pygame.K_LEFT]:
                self.current_tetromino.x -= 1
                if self.check_collision():
                    self.current_tetromino.x += 1
            if keys[pygame.K_RIGHT]:
                self.current_tetromino.x += 1
                if self.check_collision():
                    self.current_tetromino.x -= 1
            if keys[pygame.K_DOWN]:
                self.current_tetromino.y += 1
                if self.check_collision():
                    self.current_tetromino.y -= 1
            if keys[pygame.K_UP]:
                self.current_tetromino.rotate()
                if self.check_collision():
                    self.current_tetromino.rotate()
                    self.current_tetromino.rotate()
                    self.current_tetromino.rotate()

            self.current_tetromino.y += 1
            if self.check_collision():
                self.current_tetromino.y -= 1
                self.merge_tetromino()
                lines_cleared = self.clear_lines()
                self.update_score(lines_cleared)
                self.current_tetromino = Tetromino()
                if self.check_collision():
                    self.game_over = True
                self.switch_player()

            screen.fill((0, 0, 0))
            self.draw_grid(screen)
            self.draw_tetromino(screen)
            pygame.display.flip()
            clock.tick(FPS)

        pygame.quit()
        print("Scores:", self.score)
        print("Player Contributions:", self.player_contributions)

if __name__ == "__main__":
    Game().run()

