import pygame
import random

# Constants
SCREEN_WIDTH = 800
SCREEN_HEIGHT = 600
GRID_SIZE = 30
GRID_WIDTH = SCREEN_WIDTH // GRID_SIZE
GRID_HEIGHT = SCREEN_HEIGHT // GRID_SIZE
FPS = 10

# Colors
COLORS = [
    (0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
    (255, 255, 0), (255, 165, 0), (128, 0, 128), (0, 255, 255)
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]]   # J
]

class Tetromino:
    def __init__(self):
        self.shape = random.choice(SHAPES)
        self.color = random.choice(COLORS)
        self.x = GRID_WIDTH // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Game:
    def __init__(self):
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_tetromino = Tetromino()
        self.score = [0, 0, 0]
        self.player_contributions = [0, 0, 0]
        self.current_player = 0
        self.game_over = False

    def check_collision(self, offset_x=0, offset_y=0):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    new_x = self.current_tetromino.x + x + offset_x
                    new_y = self.current_tetromino.y + y + offset_y
                    if new_x < 0 or new_x >= GRID_WIDTH or new_y >= GRID_HEIGHT or self.grid[new_y][new_x]:
                        return True
        return False

    def merge_tetromino(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[self.current_tetromino.y + y][self.current_tetromino.x + x] = self.current_tetromino.color
        self.clear_lines()

    def clear_lines(self):
        lines_cleared = 0
        for i in range(GRID_HEIGHT):
            if all(self.grid[i]):
                lines_cleared += 1
                del self.grid[i]
                self.grid.insert(0, [0] * GRID_WIDTH)
        self.score[self.current_player] += lines_cleared * 100
        self.player_contributions[self.current_player] += lines_cleared * 100

    def switch_player(self):
        self.current_player = (self.current_player + 1) % 3

    def update(self):
        if not self.game_over:
            if not self.check_collision(offset_y=1):
                self.current_tetromino.y += 1
            else:
                self.merge_tetromino()
                self.current_tetromino = Tetromino()
                if self.check_collision():
                    self.game_over = True

    def draw(self, screen):
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                color = self.grid[y][x]
                if color:
                    pygame.draw.rect(screen, color, (x * GRID_SIZE, y * GRID_SIZE, GRID_SIZE, GRID_SIZE))
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, self.current_tetromino.color, 
                                     ((self.current_tetromino.x + x) * GRID_SIZE, 
                                      (self.current_tetromino.y + y) * GRID_SIZE, 
                                      GRID_SIZE, GRID_SIZE))

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Tetris for 3 Players")
        self.clock = pygame.time.Clock()
        self.game = Game()

    def run(self):
        while True:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    pygame.quit()
                    return
                if event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_LEFT:
                        if not self.game.check_collision(offset_x=-1):
                            self.game.current_tetromino.x -= 1
                    elif event.key == pygame.K_RIGHT:
                        if not self.game.check_collision(offset_x=1):
                            self.game.current_tetromino.x += 1
                    elif event.key == pygame.K_DOWN:
                        self.game.update()
                    elif event.key == pygame.K_UP:
                        self.game.current_tetromino.rotate()
                        if self.game.check_collision():
                            self.game.current_tetromino.rotate()  # Rotate back

            self.game.update()
            self.screen.fill((0, 0, 0))
            self.game.draw(self.screen)
            pygame.display.flip()
            self.clock.tick(FPS)

            if self.game.game_over:
                print("Game Over! Scores:", self.game.score)
                print("Player Contributions:", self.game.player_contributions)
                pygame.quit()
                return

if __name__ == "__main__":
    TetrisGame().run()

import pygame
import random

# Constants
SCREEN_WIDTH = 800
SCREEN_HEIGHT = 600
BLOCK_SIZE = 30
BOARD_WIDTH = 10
BOARD_HEIGHT = 20
FPS = 60

# Colors
COLORS = [
    (0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
    (255, 255, 0), (255, 165, 0), (128, 0, 128), (0, 255, 255)
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]]   # J
]

class Tetromino:
    def __init__(self):
        self.shape = random.choice(SHAPES)
        self.color = random.choice(COLORS[1:])
        self.x = BOARD_WIDTH // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Board:
    def __init__(self):
        self.grid = [[0] * BOARD_WIDTH for _ in range(BOARD_HEIGHT)]
        self.score = 0

    def clear_lines(self):
        lines_cleared = 0
        for i in range(BOARD_HEIGHT):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * BOARD_WIDTH)
                lines_cleared += 1
        self.score += lines_cleared ** 2

    def add_tetromino(self, tetromino):
        for i, row in enumerate(tetromino.shape):
            for j, value in enumerate(row):
                if value:
                    self.grid[tetromino.y + i][tetromino.x + j] = 1

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        self.clock = pygame.time.Clock()
        self.boards = [Board() for _ in range(3)]
        self.current_tetrominos = [Tetromino() for _ in range(3)]
        self.running = True
        self.scores = [0, 0, 0]

    def draw_board(self, board, offset_x, offset_y):
        for i, row in enumerate(board.grid):
            for j, value in enumerate(row):
                if value:
                    pygame.draw.rect(self.screen, COLORS[value], 
                                     (offset_x + j * BLOCK_SIZE, offset_y + i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

    def run(self):
        while self.running:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    self.running = False

            self.screen.fill((0, 0, 0))
            for i, board in enumerate(self.boards):
                self.draw_board(board, i * (SCREEN_WIDTH // 3), 0)
                self.scores[i] = board.score

            for i, tetromino in enumerate(self.current_tetrominos):
                self.draw_board(Board().add_tetromino(tetromino), i * (SCREEN_WIDTH // 3), 0)

            pygame.display.flip()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
    game = Game()
    game.run()

