    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]]   # J
]

class Tetrimino:
    def __init__(self):
        self.shape = random.choice(SHAPES)
        self.color = random.choice(COLORS)
        self.x = GRID_WIDTH // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Game:
    def __init__(self):
        self.board = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_tetrimino = Tetrimino()
        self.score = 0
        self.lines_cleared = 0

    def collide(self):
        for y, row in enumerate(self.current_tetrimino.shape):
            for x, cell in enumerate(row):
                if cell:
                    if (self.current_tetrimino.x + x < 0 or
                        self.current_tetrimino.x + x >= GRID_WIDTH or
                        self.current_tetrimino.y + y >= GRID_HEIGHT or
                        self.board[self.current_tetrimino.y + y][self.current_tetrimino.x + x]):
                        return True
        return False

    def merge(self):
        for y, row in enumerate(self.current_tetrimino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.board[self.current_tetrimino.y + y][self.current_tetrimino.x + x] = self.current_tetrimino.color
        self.clear_lines()

    def clear_lines(self):
        lines_to_clear = [i for i, row in enumerate(self.board) if all(row)]
        for i in lines_to_clear:
            del self.board[i]
            self.board.insert(0, [0] * GRID_WIDTH)
            self.lines_cleared += 1
            self.score += 100

    def drop_tetrimino(self):
        self.current_tetrimino.y += 1
        if self.collide():
            self.current_tetrimino.y -= 1
            self.merge()
            self.current_tetrimino = Tetrimino()
            if self.collide():
                return False
        return True

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        self.clock = pygame.time.Clock()
        self.games = [Game() for _ in range(3)]
        self.running = True

    def draw_board(self, game, offset_x):
        for y, row in enumerate(game.board):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(self.screen, cell, (offset_x + x * GRID_SIZE, y * GRID_SIZE, GRID_SIZE, GRID_SIZE))
        for y, row in enumerate(game.current_tetrimino.shape):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(self.screen, game.current_tetrimino.color, (offset_x + (game.current_tetrimino.x + x) * GRID_SIZE, (game.current_tetrimino.y + y) * GRID_SIZE, GRID_SIZE, GRID_SIZE))

    def run(self):
        while self.running:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    self.running = False

            for i, game in enumerate(self.games):
                if not game.drop_tetrimino():
                    self.running = False

            self.screen.fill((0, 0, 0))
            for i, game in enumerate(self.games):
                self.draw_board(game, i * (SCREEN_WIDTH // 3))

            pygame.display.flip()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
    TetrisGame().run()

