class Tetromino:
    def __init__(self, shape):
        self.shape = shape
        self.color = random.choice(COLORS[1:])
        self.x = GRID_WIDTH // 2 - len(shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class TetrisGame:
    def __init__(self):
        self.board = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_tetromino = self.new_tetromino()
        self.score = [0, 0, 0]
        self.player_turn = 0

    def new_tetromino(self):
        return Tetromino(random.choice(SHAPES))

    def valid_position(self, tetromino, offset_x=0, offset_y=0):
        for y, row in enumerate(tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    new_x = tetromino.x + x + offset_x
                    new_y = tetromino.y + y + offset_y
                    if new_x < 0 or new_x >= GRID_WIDTH or new_y >= GRID_HEIGHT or self.board[new_y][new_x]:
                        return False
        return True

    def merge_tetromino(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.board[self.current_tetromino.y + y][self.current_tetromino.x + x] = self.current_tetromino.color

    def clear_lines(self):
        lines_cleared = 0
        for i in range(GRID_HEIGHT):
            if all(self.board[i]):
                del self.board[i]
                self.board.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1
        return lines_cleared

    def update(self):
        if self.valid_position(self.current_tetromino, 0, 1):
            self.current_tetromino.y += 1
        else:
            self.merge_tetromino()
            lines_cleared = self.clear_lines()
            self.score[self.player_turn] += lines_cleared * 100
            self.current_tetromino = self.new_tetromino()
            if not self.valid_position(self.current_tetromino):
                self.reset_game()

    def reset_game(self):
        self.board = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.score = [0, 0, 0]

