        for y, row in enumerate(self.game.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(self.screen, self.game.current_tetromino.color,
                                     ((self.game.current_tetromino.x + x) * GRID_SIZE,
                                      (self.game.current_tetromino.y + y) * GRID_SIZE, GRID_SIZE, GRID_SIZE))

    def draw_scores(self):
        font = pygame.font.Font(None, 36)
        for i in range(3):
            score_text = font.render(f'Player {i + 1}: {self.game.score[i]}', True, (255, 255, 255))
            self.screen.blit(score_text, (10, 10 + i * 30))

    def run(self):
        while self.running:
            self.screen.fill((0, 0, 0))
            self.draw_board()
            self.draw_tetromino()
            self.draw_scores()
            pygame.display.flip()
            self.game.update()
            self.clock.tick(FPS)

            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    self.running = False
                elif event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_LEFT and self.game.valid_position(self.game.current_tetromino, -1):
                        self.game.current_tetromino.x -= 1
                    elif event.key == pygame.K_RIGHT and self.game.valid_position(self.game.current_tetromino, 1):
                        self.game.current_tetromino.x += 1
                    elif event.key == pygame.K_DOWN:
                        self.game.update()
                    elif event.key == pygame.K_UP:
                        self.game.current_tetromino.rotate()
                        if not self.game.valid_position(self.game.current_tetromino):
                            self.game.current_tetromino.rotate()  # Rotate back

            if self.game.current_tetromino.y >= GRID_HEIGHT - 1 or not self.game.valid_position(self.game.current_tetromino, 0, 1):
                self.game.merge_tetromino()
                self.game.clear_lines()
                self.game.switch_player()

        pygame.quit()

if __name__ == "__main__":
