import pygame
import random

# Constants
SCREEN_WIDTH = 800
SCREEN_HEIGHT = 600
GRID_SIZE = 30
GRID_WIDTH = SCREEN_WIDTH // GRID_SIZE
GRID_HEIGHT = SCREEN_HEIGHT // GRID_SIZE
FPS = 10

# Colors
COLORS = [
    (0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
    (255, 255, 0), (255, 165, 0), (128, 0, 128), (0, 255, 255)
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]]   # J
]

class Tetromino:
    def __init__(self, shape):
        self.shape = shape
        self.color = COLORS[random.randint(1, len(COLORS) - 1)]
        self.x = GRID_WIDTH // 2 - len(shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Board:
    def __init__(self):
        self.grid = [[0 for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]
        self.score = 0

    def clear_lines(self):
        lines_cleared = 0
        for i in range(GRID_HEIGHT):
            if all(self.grid[i]):
                lines_cleared += 1
                del self.grid[i]
                self.grid.insert(0, [0 for _ in range(GRID_WIDTH)])
        self.score += lines_cleared * 100

    def add_tetromino(self, tetromino):
        for i, row in enumerate(tetromino.shape):
            for j, value in enumerate(row):
                if value:
                    self.grid[tetromino.y + i][tetromino.x + j] = 1

class Player:
    def __init__(self, player_id):
        self.id = player_id
        self.board = Board()
        self.current_tetromino = None
        self.score = 0

    def new_tetromino(self):
        self.current_tetromino = Tetromino(random.choice(SHAPES))

    def update_score(self):
        self.score += self.board.score
        self.board.score = 0

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        self.clock = pygame.time.Clock()
        self.players = [Player(i) for i in range(3)]
        self.running = True
        self.current_player_index = 0

    def run(self):
        while self.running:
            self.handle_events()
            self.update()
            self.draw()
            self.clock.tick(FPS)

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False

    def update(self):
        current_player = self.players[self.current_player_index]
        if current_player.current_tetromino is None:
            current_player.new_tetromino()
        else:
            current_player.current_tetromino.y += 1
            if self.check_collision(current_player.current_tetromino):
                current_player.current_tetromino.y -= 1
                current_player.board.add_tetromino(current_player.current_tetromino)
