class Game:
    def __init__(self):
        self.board = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_tetromino = Tetromino()
        self.score = 0
        self.game_over = False

    def collide(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    if (self.current_tetromino.x + x < 0 or
                        self.current_tetromino.x + x >= GRID_WIDTH or
                        self.current_tetromino.y + y >= GRID_HEIGHT or
                        self.board[self.current_tetromino.y + y][self.current_tetromino.x + x]):
                        return True
        return False

    def merge(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.board[self.current_tetromino.y + y][self.current_tetromino.x + x] = self.current_tetromino.color
        self.clear_lines()

    def clear_lines(self):
        lines_to_clear = [i for i, row in enumerate(self.board) if all(row)]
        for i in lines_to_clear:
