        self.current_tetromino.y += 1
        if self.collide():
            self.current_tetromino.y -= 1
            self.merge()
            self.current_tetromino = Tetromino()
            if self.collide():
                self.game_over = True

    def move(self, dx):
        self.current_tetromino.x += dx
        if self.collide():
            self.current_tetromino.x -= dx

